from __future__ import annotations

import os

from langchain_huggingface import HuggingFaceEndpoint
from langchain_openai import ChatOpenAI


def get_llm(provider: str, openai_model: str, huggingface_repo_id: str, temperature: float = 0.2):
    provider = provider.lower()

    if provider == "openai":
        if not os.getenv("OPENAI_API_KEY"):
            raise ValueError("OPENAI_API_KEY is missing. Set it in .env or environment variables.")
        return ChatOpenAI(model=openai_model, temperature=temperature)

    if provider == "huggingface":
        token = os.getenv("HUGGINGFACEHUB_API_TOKEN") or os.getenv("HF_TOKEN")
        if not token:
            raise ValueError(
                "HUGGINGFACEHUB_API_TOKEN (or HF_TOKEN) is missing. Set it in .env or environment variables."
            )
        return HuggingFaceEndpoint(
            model=huggingface_repo_id,
            repo_id=huggingface_repo_id,
            huggingfacehub_api_token=token,
            temperature=temperature,
            max_new_tokens=512,
        )

    raise ValueError("Unsupported provider. Use 'openai' or 'huggingface'.")

from __future__ import annotations

import os

from langchain_huggingface import HuggingFaceEndpoint
from langchain_openai import ChatOpenAI


def get_llm(provider: str, openai_model: str, huggingface_repo_id: str, temperature: float = 0.2):
    provider = provider.lower()

    if provider == "openai":
        if not os.getenv("OPENAI_API_KEY"):
            raise ValueError("OPENAI_API_KEY is missing. Set it in .env or environment variables.")
        return ChatOpenAI(model=openai_model, temperature=temperature)

    if provider == "huggingface":
        token = os.getenv("HUGGINGFACEHUB_API_TOKEN") or os.getenv("HF_TOKEN")
        if not token:
            raise ValueError(
                "HUGGINGFACEHUB_API_TOKEN (or HF_TOKEN) is missing. Set it in .env or environment variables."
            )
        return HuggingFaceEndpoint(
            repo_id=huggingface_repo_id,
            huggingfacehub_api_token=token,
            task="text-generation",
            streaming=False,
            temperature=temperature,
            max_new_tokens=512,
        )

    raise ValueError("Unsupported provider. Use 'openai' or 'huggingface'.")

from __future__ import annotations
from pathlib import Path
import streamlit as st
from app.config import settings from app.embeddings.embedder import get_embeddings from app.ingestion.chunking import chunk_documents from app.ingestion.loader import load_pdfs from app.llm.generator import get_llm from app.retrieval.retriever import build_retriever from app.utils.helpers import unique_sources from app.vectorstore.chroma_store import build_store, load_store from app.workflow.langgraph_flow import build_graph
st.set_page_config(page_title="RAG Customer Support", page_icon="", layout="wide")
def index_documents(force_reindex: bool = False): docs = load_pdfs(settings.data_dir) chunked = chunk_documents(docs, settings.chunk_size, settings.chunk_overlap) embeddings = get_embeddings(settings.embedding_model)
if force_reindex: # Build a fresh collection from current data. vectorstore = build_store(chunked, embeddings, settings.chroma_dir) else: marker = settings.chroma_dir / "chroma.sqlite3" vectorstore = ( load_store(embeddings, settings.chroma_dir) if marker.exists() else build_store(chunked, embeddings, settings.chroma_dir) )
retriever = build_retriever(vectorstore, top_k=settings.top_k) llm = get_llm(settings.provider, settings.openai_model, settings.huggingface_repo_id) graph = build_graph(retriever, llm) return graph
def init_state(): if "graph" not in st.session_state: st.session_state.graph = None if "last_sources" not in st.session_state: st.session_state.last_sources = []
def main(): init_state()
st.title("RAG-Based Customer Support Assistant") st.caption("LangChain + ChromaDB + LangGraph + HITL")
with st.sidebar: st.subheader("Pipeline Settings") st.write(f"Provider: `{settings.provider}`") st.write(f"Embedding model: `{settings.embedding_model}`") st.write(f"Top-K retrieval: `{settings.top_k}`")
if st.button("Build / Refresh Index", type="primary"): try: st.session_state.graph = index_documents(force_reindex=True) st.success("Vector index refreshed.") except Exception as exc: # noqa: BLE001 st.error(f"Indexing failed: {exc}")
data_dir = Path(settings.data_dir) pdf_count = len(list(data_dir.glob("*.pdf"))) st.info(f"PDF files found in data/: {pdf_count}")
if st.session_state.graph is None: try: st.session_state.graph = index_documents(force_reindex=False) except Exception as exc: # noqa: BLE001 st.warning(f"Initialize pipeline first. Reason: {exc}")
query = st.text_input("Ask your question") if st.button("Get Answer"): if not query.strip(): st.warning("Please enter a query.") return if st.session_state.graph is None: st.error("Pipeline not initialized. Add PDF(s) in data/ and build index.") return
with st.spinner("Thinking..."): result = st.session_state.graph.invoke({"query": query}) docs = result.get("docs", []) st.session_state.last_sources = unique_sources(docs)
st.subheader("Response") st.write(result.get("final_answer", "No answer generated."))
if result.get("needs_human"): st.error("HITL Triggered: Escalation recommended.")
if st.session_state.last_sources: st.subheader("Sources") for src in st.session_state.last_sources: st.write(f"- {src}")
if __name__ == "__main__": main()

from __future__ import annotations

from typing import Iterable

from langchain_core.documents import Document


def format_docs(docs: Iterable[Document]) -> str:
    return "\n\n".join(doc.page_content for doc in docs)


def unique_sources(docs: Iterable[Document]) -> list[str]:
    sources = []
    seen = set()
    for doc in docs:
        source = doc.metadata.get("source", "unknown")
        if source not in seen:
            seen.add(source)
            sources.append(source)
    return sources

from __future__ import annotations

import re
from typing import Iterable

from langchain_core.documents import Document


def format_docs(docs: Iterable[Document]) -> str:
    return "\n\n".join(doc.page_content for doc in docs)


def unique_sources(docs: Iterable[Document]) -> list[str]:
    sources = []
    seen = set()
    for doc in docs:
        source = doc.metadata.get("source", "unknown")
        if source not in seen:
            seen.add(source)
            sources.append(source)
    return sources


def build_fallback_answer(query: str, context: str, max_points: int = 3) -> str:
    cleaned_context = context.strip()
    if not cleaned_context:
        return "I do not know based on provided documents."

    # Keep meaningful unique lines to avoid repeated chunk output.
    raw_lines = [re.sub(r"\s+", " ", line).strip() for line in cleaned_context.splitlines()]
    lines = [line for line in raw_lines if len(line) > 20]

    unique_lines: list[str] = []
    seen = set()
    for line in lines:
        key = line.casefold()
        if key not in seen:
            seen.add(key)
            unique_lines.append(line)

    # Prioritize lines matching the user query keywords.
    query_terms = [w for w in re.findall(r"[a-zA-Z]+", query.lower()) if len(w) > 3]
    ranked: list[str] = []
    for line in unique_lines:
        line_low = line.lower()
        if any(term in line_low for term in query_terms):
            ranked.append(line)

    if not ranked:
        ranked = unique_lines

    selected = ranked[:max_points]
    if not selected:
        return "I do not know based on provided documents."

    bullets = "\n".join(f"- {line}" for line in selected)
    return f"Based on the documents:\n{bullets}"

from __future__ import annotations

from typing import Any

from typing_extensions import TypedDict

from langchain_core.output_parsers import StrOutputParser
from langchain_core.prompts import PromptTemplate
from langgraph.graph import END, StateGraph

from app.hitl.human_loop import should_escalate
from app.utils.helpers import format_docs


class GraphState(TypedDict, total=False):
    query: str
    docs: list[Any]
    context: str
    answer: str
    needs_human: bool
    final_answer: str


def build_graph(retriever, llm):
    prompt = PromptTemplate.from_template(
        """You are a customer support assistant. Use only the given context.
If the answer is not in context, say exactly: I do not know based on provided documents.

Context:
{context}

Question:
{query}

Answer in a concise and helpful way."""
    )
    generation_chain = prompt | llm | StrOutputParser()

    def retrieve_node(state: GraphState) -> GraphState:
        docs = retriever.invoke(state["query"])
        context = format_docs(docs)
        return {"docs": docs, "context": context}

    def generate_node(state: GraphState) -> GraphState:
        answer = generation_chain.invoke({"query": state["query"], "context": state["context"]})
        return {"answer": answer}

    def decide_node(state: GraphState) -> GraphState:
        needs_human = should_escalate(state.get("answer", ""), state.get("context", ""), state["query"])
        return {"needs_human": needs_human}

    def human_node(state: GraphState) -> GraphState:
        return {
            "final_answer": (
                "Escalated to human support: I could not confidently answer from the available documents."
            )
        }

    def finalize_node(state: GraphState) -> GraphState:
        return {"final_answer": state.get("answer", "")}

    graph = StateGraph(GraphState)
    graph.add_node("retrieve", retrieve_node)
    graph.add_node("generate", generate_node)
    graph.add_node("decide", decide_node)
    graph.add_node("human", human_node)
    graph.add_node("finalize", finalize_node)

    graph.set_entry_point("retrieve")
    graph.add_edge("retrieve", "generate")
    graph.add_edge("generate", "decide")

    def route_after_decide(state: GraphState) -> str:
        return "human" if state.get("needs_human") else "finalize"

    graph.add_conditional_edges(
        "decide",
        route_after_decide,
        {"human": "human", "finalize": "finalize"},
    )
    graph.add_edge("human", END)
    graph.add_edge("finalize", END)

    return graph.compile()

from __future__ import annotations

from typing import Any

from typing_extensions import TypedDict

from langchain_core.output_parsers import StrOutputParser
from langchain_core.prompts import PromptTemplate
from langgraph.graph import END, StateGraph

from app.hitl.human_loop import should_escalate
from app.utils.helpers import build_fallback_answer, format_docs


class GraphState(TypedDict, total=False):
    query: str
    docs: list[Any]
    context: str
    answer: str
    generation_error: str
    generation_warning: str
    needs_human: bool
    final_answer: str


def build_graph(retriever, llm):
    prompt = PromptTemplate.from_template(
        """You are a customer support assistant. Use only the given context.
If the answer is not in context, say exactly: I do not know based on provided documents.

Context:
{context}

Question:
{query}

Answer in a concise and helpful way."""
    )
    generation_chain = prompt | llm | StrOutputParser()

    def _normalize_answer(raw: Any) -> str:
        if raw is None:
            return ""
        if isinstance(raw, str):
            return raw.strip()
        content = getattr(raw, "content", None)
        if isinstance(content, str):
            return content.strip()
        return str(raw).strip()

    def _context_fallback(query: str, context: str) -> str:
        return build_fallback_answer(query=query, context=context, max_points=3)

    def retrieve_node(state: GraphState) -> GraphState:
        docs = retriever.invoke(state["query"])
        context = format_docs(docs)
        return {"docs": docs, "context": context}

    def generate_node(state: GraphState) -> GraphState:
        try:
            raw_answer = generation_chain.invoke(
                {"query": state["query"], "context": state.get("context", "")}
            )
            answer = _normalize_answer(raw_answer)
            if not answer:
                fallback = _context_fallback(state["query"], state.get("context", ""))
                return {
                    "answer": fallback,
                    "generation_warning": "empty_generation",
                }
            return {"answer": answer}
        except Exception as exc:  # noqa: BLE001
            # Keep app responsive even when provider runtime errors occur.
            fallback = _context_fallback(state["query"], state.get("context", ""))
            return {
                "answer": fallback,
                "generation_warning": f"{type(exc).__name__}: {exc}",
            }

    def decide_node(state: GraphState) -> GraphState:
        no_answer = not state.get("answer", "").strip()
        needs_human = no_answer or bool(state.get("generation_error")) or should_escalate(
            state.get("answer", ""), state.get("context", ""), state["query"]
        )
        return {"needs_human": needs_human}

    def human_node(state: GraphState) -> GraphState:
        return {
            "final_answer": (
                "Escalated to human support: I could not confidently answer from the available documents."
            )
        }

    def finalize_node(state: GraphState) -> GraphState:
        return {"final_answer": state.get("answer", "")}

    graph = StateGraph(GraphState)
    graph.add_node("retrieve", retrieve_node)
    graph.add_node("generate", generate_node)
    graph.add_node("decide", decide_node)
    graph.add_node("human", human_node)
    graph.add_node("finalize", finalize_node)

    graph.set_entry_point("retrieve")
    graph.add_edge("retrieve", "generate")
    graph.add_edge("generate", "decide")

    def route_after_decide(state: GraphState) -> str:
        return "human" if state.get("needs_human") else "finalize"

    graph.add_conditional_edges(
        "decide",
        route_after_decide,
        {"human": "human", "finalize": "finalize"},
    )
    graph.add_edge("human", END)
    graph.add_edge("finalize", END)

    return graph.compile()
